  function hasRealData(draw) {
    if (!draw) return false;
    var dd = draw.drawDate;
    if (!(dd && new Date(dd + "+03:00") <= new Date)) return false;
    if (draw.main && draw.main.length > 0) return true;
    var det = draw.digitalDetails;
    if (det) {
      if (Array.isArray(det) && det.length > 0) {
        if (typeof det[0] === "number") return true;
        if (typeof det[0] === "object" && det[0].categoryNumber) return true;
      }
    }
    return false;
  }

  function extractNumbers(draw) {
    if (!draw) return {main:[], extra:[]};
    if (draw.main && draw.main.length > 0) {
      var ext = draw.sub || draw.extra || [];
      if (!Array.isArray(ext)) ext = [ext];
      return {main: draw.main, extra: ext};
    }
    if (draw.digitalDetails) {
      var det = draw.digitalDetails;
      if (Array.isArray(det)) {
        if (typeof det[0] === "number") {
          var e = draw.sub || draw.extra || [];
          if (!Array.isArray(e)) e = [e];
          return {main: det, extra: e};
        }
        var mainArr = [], extraArr = [];
        for (var i = 0; i < det.length; i++) {
          if (det[i].numbers && Array.isArray(det[i].numbers)) {
            mainArr = det[i].numbers;
          }
          if (void 0 !== det[i].extraNumber) {
            extraArr = [det[i].extraNumber];
          }
          if (det[i].additionalNumbers) {
            extraArr = det[i].additionalNumbers;
          }
        }
        if (mainArr.length > 0) {
          if (extraArr.length === 0) {
            extraArr = draw.sub || draw.extra || [];
            if (!Array.isArray(extraArr)) extraArr = [extraArr];
          }
          return {main: mainArr, extra: extraArr};
        }
        for (var j = 0; j < det.length; j++) {
          if (typeof det[j].value === "number") mainArr.push(det[j].value);
          else if (typeof det[j].number === "number") mainArr.push(det[j].number);
        }
        if (mainArr.length > 0) return {main: mainArr, extra: draw.sub || draw.extra || []};
