      if (typeof det === "object" && !Array.isArray(det)) {
        if (det.numbers) return {main: det.numbers, extra: det.sub ? [det.sub] : det.extraNumber ? [det.extraNumber] : det.additionalNumbers || []};
        if (det.main) return {main: det.main, extra: det.extra || []};
        if (det.fields) return {main: det.fields, extra: []};
      }
    }
    var leftover = draw.sub || draw.extra || [];
    if (!Array.isArray(leftover)) leftover = [leftover];
    return {main: draw.main || [], extra: leftover};
  }

