          logFn("–Я–Њ—Б–ї–µ–і–љ–Є–є –њ—А–Њ—И–µ–і—И–Є–є: #" + pad6(result.num) + " –і–∞—В–∞=" + data.drawDate, "#4CAF50");
        }
      }
      if (!result) logFn("nearestDraw –љ–∞–є–і–µ–љ, –љ–Њ –љ–µ —Г–і–∞–ї–Њ—Б—М –љ–∞–є—В–Є –њ—А–Њ—И–µ–і—И–Є–є —В–Є—А–∞–ґ.", "#FF9800");
    }

    if (!result) {
      // –Р–і–∞–њ—В–Є–≤–љ—Л–є –њ–Њ–Є—Б–Ї —Б –њ—А–Њ–±–∞–Љ–Є
      logFn("–Р–і–∞–њ—В–Є–≤–љ—Л–є –±–Є–љ–∞—А–љ—Л–є –њ–Њ–Є—Б–Ї...", "#666");
      var probes = [500,1000,2000,5000,10000,20000,30000,40000,50000,60000,70000,80000,90000,100000];
      var probeResults = [];
      var batchPromises = [];
      for (var p = 0; p < probes.length; p++) {
        batchPromises.push(fetchDraw(productId, probes[p], 1));
      }
      var probeData = await Promise.all(batchPromises);

      var highFound = -1, lowEmpty = -1;
      for (var kd = 0; kd < probes.length; kd++) {
        if (probeData[kd] && hasRealData(probeData[kd])) {
          highFound = probes[kd];
        } else if (highFound > 0 && lowEmpty < 0) {
          lowEmpty = probes[kd];
        }
      }
      logFn("–Я—А–Њ–±—Лъ –Є–Љ–µ—В—М –љ–Є–ґ–љ–Є—П "И∞ highFound + " вАУ " + (lowEmpty > 0 ? lowEmpty : "?"), "#00BCD4");
