        }
        var finalData = await fetchDraw(productId, lo, 1);
        if (finalData && hasRealData(finalData)) {
          result = {num: lo, data: finalData, format: "sequential", iterations: iters};
          logFn("–Э–∞–є–і–µ–љ: #" + pad6(lo) + " (" + iters + " –Є—В–µ—А–∞—Ж–Є–є)", "#4CAF50");
        } else {
          // –Ш–і—С–Љ –љ–∞–Ј–∞–і
          for (var back = 1; back <= 100 && !result; back++) {
            if (state.abortFlag) return null;
            var backData = await fetchDraw(productId, lo - back, 1);
            if (backData && hasRealData(backData)) {
              result = {num: lo - back, data: backData, format: "sequential", iterations: iters + back};
              logFn("–Э–∞–є–і–µ–љ: #" + pad6(lo - back) + " (–љ–∞–Ј–∞–і " + back + ")", "#4CAF50");
            }
          }
        }
      }
    }

    // Fallback: DDMMYY —Д–Њ—А–Љ–∞—В
