      logFn("–Я—А–Њ–±—Г–µ–Љ DDMMYY —Д–Њ—А–Љ–∞—В...", "#666");
      var now = new Date();
      for (var d = 0; d < 60 && !result; d++) {
        if (state.abortFlag) return null;
        var dt = new Date(now.getTime() - 86400000 * d);
        var ddStr = pad2(dt.getDate()) + pad2(dt.getMonth()+1) + String(dt.getFullYear()).substring(2);
        var ddData = await fetchDraw(productId, parseInt(ddStr, 10), 0);
        if (ddData && hasRealData(ddData)) {
          result = {num: parseInt(ddStr, 10), data: ddData, format: "date_ddmmyy", iterations: d+1};
        }
      }
    }

    if (result) {
      state.latestDrawNum = result.num;
      state.drawNumFormat = result.format;
      state.lotteryType = result.data.type;
      if (!state.basePrice) state.basePrice = result.data.basePrice || 0;
      cacheSet("scan_" + productId, {
        num: result.num,
        format: result.format,
        type: result.data.type,
        basePrice: state.basePrice
      });
    }

    return result;
  }

