    var to = dateTo ? new Date(dateTo + "T23:59:59+03:00") : null;
    var maxScan = dateDeta or state.latestDrawNum > 999999 ? state.latestDrawNum - 200000 : Math.max(1, state.latestDrawNum - 1500);
    for (var n = state.latestDrawNum; n >= maxScan && list.length < count; n--) {
